	public static final class MinusAlternativeRule extends AbstractRule {
		public MinusAlternativeRule() {
			super("minus-alternatives", RuleKind.TRANSFORMATION, 55);
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return expression.logical() && expression.tupleExpr() instanceof Difference;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			Difference difference = (Difference) expression.tupleExpr();
			List<RuleApplication> applications = new ArrayList<>(4);
			RuleApplication redundantPatternFilter = redundantPatternMinusFilterAlternative(expression, difference,
					goal);
			if (redundantPatternFilter != null) {
				applications.add(redundantPatternFilter);
			}
			if (difference.getLeftArg()instanceof Union union && !union.isVariableScopeChange()) {
				RuleProof proof = proof(semanticScope(goal), Set.of("leftUnionBranchesCompatible", "rhsScopeSafe"),
						"MINUS distributes over a safe left UNION as a costed alternative");
				applications.add(RuleApplication.transformation(expression.groupId(),
						new Union(new Difference(union.getLeftArg().clone(), difference.getRightArg().clone()),
								new Difference(union.getRightArg().clone(), difference.getRightArg().clone())),
						proof));
			}
			if (difference.getLeftArg()instanceof Difference inner) {
				RuleProof proof = proof(semanticScope(goal), Set.of("rhsIndependent", "bagCompatible"),
						"chained MINUS RHSs can be combined or reordered when treated as alternatives");
				applications.add(RuleApplication.transformation(expression.groupId(),
						new Difference(inner.getLeftArg().clone(), new Union(inner.getRightArg().clone(),
								difference.getRightArg().clone())),
						proof));
				applications.add(RuleApplication.transformation(expression.groupId(),
						new Difference(new Difference(inner.getLeftArg().clone(), difference.getRightArg().clone()),
								inner.getRightArg().clone()),
						proof));
			}
			return applications;
		}

		private RuleApplication redundantPatternMinusFilterAlternative(MemoExpr expression, Difference difference,
				OptimizationGoal goal) {
			if (!(difference.getRightArg()instanceof Filter rightFilter)
					|| !(rightFilter.getArg()instanceof StatementPattern rightPattern)) {
				return null;
			}

			Set<String> conditionVars = plannerNames(VarNameCollector.process(rightFilter.getCondition()));
			if (!rightPattern.getBindingNames().containsAll(conditionVars)
					|| !difference.getLeftArg().getAssuredBindingNames().containsAll(conditionVars)
					|| !isSafeTotalMinusLocalCondition(rightFilter.getCondition(), conditionVars)
					|| !containsEquivalentRequiredPattern(difference.getLeftArg(), rightPattern)) {
				return null;
			}

			RuleProof proof = proof(semanticScope(goal),
					Set.of("rhsPatternRequiredOnLeft", "conditionVarsAssuredByLeft", "totalStringFilter"),
					"MINUS over an already-required RHS pattern plus total local filter is a negated left filter");
			return RuleApplication.transformation(expression.groupId(),
					new Filter(difference.getLeftArg().clone(), new Not(rightFilter.getCondition().clone())), proof);
		}
	}

	public static final class GenericImplementationRule extends AbstractRule {
		private final Predicate<TupleExpr> implementationAllowed;

		public GenericImplementationRule() {
			this(ignored -> true);
		}

		public GenericImplementationRule(Predicate<TupleExpr> implementationAllowed) {
			super("generic-physical-implementation", RuleKind.IMPLEMENTATION, 10);
			this.implementationAllowed = implementationAllowed == null ? ignored -> true : implementationAllowed;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return expression.logical() && implementationAllowed.test(expression.tupleExpr());
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			PhysicalProperties delivered = PhysicalProperties.builder()
					.boundVars(expression.tupleExpr() == null ? Set.of() : expression.tupleExpr().getBindingNames())
					.duplicateBehavior(PhysicalProperties.DuplicateBehavior.PRESERVES)
					.materialization(PhysicalProperties.Materialization.STREAMING)
					.build();
			RuleProof proof = proof(semanticScope(goal), Set.of("rdf4jIteratorImplementation"),
					"existing RDF4J algebra node remains a legal physical implementation");
			return List.of(RuleApplication.physical(expression.groupId(), expression.tupleExpr().clone(), delivered,
					CostVector.ZERO, proof, "generic"));
		}
	}

	public static final class DistinctEnforcerRule extends AbstractRule {
		public DistinctEnforcerRule() {
			super("distinct-enforcer", RuleKind.ENFORCER, 20);
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return goal != null
					&& !goal.requiredProperties().distinctVars().isEmpty()
					&& !expression.deliveredProperties()
							.distinctVars()
							.containsAll(goal.requiredProperties().distinctVars());
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			Distinct distinct = new Distinct(expression.tupleExpr().clone());
			PhysicalProperties delivered = expression.deliveredProperties()
					.withDistinctVars(goal.requiredProperties().distinctVars())
					.mergedWith(PhysicalProperties.builder()
							.duplicateBehavior(PhysicalProperties.DuplicateBehavior.ELIMINATES)
							.build());
			RuleProof proof = proof(semanticScope(goal), Set.of("enforcesDistinct"),
					"DISTINCT enforcer supplies required duplicate behavior");
			return List.of(RuleApplication.enforcer(expression.groupId(), distinct, delivered, CostVector.ZERO, proof,
					"distinct"));
		}
	}

